mapper.sql:
SELECT M1.ID, M1.BHT_ID, M1.CUSTOMER_CODE, M1.CUSTOMER_NAME, M1.CUSTOMER_SHORT_NAME, M1.CUSTOMER_TYPE_CODE, M3.DICT_LABEL CUSTOMER_TYPE_LABEL, M1.INVOICE, M1.TIN, M1.BANK, M1.BANK_ACCOUNT, M1.ADDRESS, M1.TELEPHONE_NUMBER, M1.CONTACT, M1.CONTACT_NUMBER, M1.CONTACT_ADDRESS, M1.STATUS, M2.NM AS STATUS_LABEL, M1.REMARK, M1.IDEA, M1.CUSTOMER_PROPERTY_NAMES, M1.CREATE_BY, M1.CREATE_BY_NAME, M1.CREATE_TIME, M1.UPDATE_BY, M1.UPDATE_BY_NAME, M1.UPDATE_TIME, M1.APPROVAL_BY, M1.APPROVAL_NAME, M1.APPROVAL_TIME, M1.IS_CREDIT, M1.CUSTOMER_NAME_EAS, M1.CUSTOMER_CODE_EAS, M1.TAXATION_INVOICE, M1.TAXATION_INVOICE_CODE FROM T_BUS_CUSTOMER M1 left join M_CONSTANTS M2 ON M1.STATUS=M2.CD and M2.TYPE_CD='CUSTOMER_STATUS' left join M_DICT_DATA M3 ON M1.CUSTOMER_TYPE_CODE=M3.DICT_VALUE and M3.DICT_TYPE='CUSTOMER_TYPE'
and M1.CUSTOMER_SHORT_NAME LIKE #{customerShortName}
and M1.CUSTOMER_CODE LIKE #{customerCode}
and (M1.CUSTOMER_NAME LIKE #{customerName} OR M1.CUSTOMER_SHORT_NAME LIKE #{customerName})
and M1.CUSTOMER_TYPE_CODE = #{customerTypeCode}
AND M1.ID IN (SELECT CUSTOMER_ID FROM T_BUS_CUSTOMER_PROPERTY WHERE CUSTOMER_PROPERTY_CODE = #{customerPropertyCode})
and M1.STATUS = #{status}
and M1.BHT_ID = #{bhtId}
ORDER BY CASE M2.NM WHEN '待审核' THEN 1 WHEN '已审核' THEN 2 WHEN '停用' THEN 3 ELSE 4 END, M1.CREATE_TIME DESC

mapper.insert:
INSERT INTO T_BUS_CUSTOMER_CONTACT( ID, CUSTOMER_ID, CONTACT_NAME, MOBILE, BIRTHDAY, ALLOW_SMS, SEX, OFFICE_CODE, OFFICE_NAME, CREATE_BY, CREATE_BY_NAME, CREATE_TIME) (
SELECT #{item.id, jdbcType=BIGINT}, #{item.customerId, jdbcType=BIGINT}, #{item.contactName, jdbcType=VARCHAR}, #{item.mobile, jdbcType=VARCHAR}, #{item.birthday, jdbcType=TIMESTAMP}, #{item.allowSms, jdbcType=VARCHAR}, #{item.sex, jdbcType=VARCHAR}, #{item.officeCode, jdbcType=VARCHAR}, #{item.officeName, jdbcType=VARCHAR}, #{item.loginUserId, jdbcType=BIGINT}, #{item.loginUserName, jdbcType=VARCHAR}, #{item.now,jdbcType=TIMESTAMP} from dual
)

mapper.select:
SELECT COUNT(*) from T_BUS_CUSTOMER TBC
LEFT JOIN T_BUS_CARGO_INFO  TBCI ON TBCI.CARGO_OWNER_ID = TBC.ID
WHERE TBCI.ID IS NOT NULL AND TBC.ID = #{id}

SELECT
CUSTOMER_CODE, CUSTOMER_NAME, CUSTOMER_SHORT_NAME
FROM
T_BUS_CUSTOMER

    id != #{id}

        and CUSTOMER_CODE = #{customerCode}


        and CUSTOMER_NAME = #{customerName}


        and CUSTOMER_SHORT_NAME = #{customerShortName}
